#include <iostream>
using namespace std;

int main() {
    int value = 42;
    int* ptr = &value;

    cout << "Before change: value = " << value << endl;

    // Dereference to read
    int copy = *ptr;
    cout << "copy from pointer: " << copy << endl;

    // Dereference to modify the original variable
    *ptr = 99;
    cout << "After *ptr = 99: value = " << value << endl;

    // ptr still points to value
    (*ptr)++;   // increment the value at that address
    cout << "After (*ptr)++: value = " << value << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int* ptr1 = nullptr;  // modern C++
    int* ptr2 = NULL;     // old C style
    int* ptr3 = 0;        // also works

    if (ptr1 == nullptr) {
        cout << "ptr1 is null" << endl;
    }

    // Dereferencing a null pointer causes crash (segmentation fault)
    // int* bad = nullptr;
    // *bad = 5;  // DON'T DO THIS

    // Always check before dereferencing
    int* ptr = nullptr;
    if (ptr != nullptr) {
        *ptr = 10;
    } else {
        cout << "ptr is null, safe to skip" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

void increment(int* p) {
    (*p)++;   // modify the value at the address
}

void swap(int* a, int* b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int main() {
    int x = 5;
    cout << "Before increment: " << x << endl;
    increment(&x);   // pass address of x
    cout << "After increment: " << x << endl;

    int p = 10, q = 20;
    cout << "Before swap: p=" << p << ", q=" << q << endl;
    swap(&p, &q);
    cout << "After swap: p=" << p << ", q=" << q << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int arr[] = {10, 20, 30, 40, 50};
    int* ptr = arr;  // points to first element (arr[0])

    cout << "ptr points to: " << *ptr << endl;     // 10
    ptr++;
    cout << "After ptr++: " << *ptr << endl;       // 20
    ptr += 2;
    cout << "After ptr+=2: " << *ptr << endl;      // 40
    ptr--;
    cout << "After ptr--: " << *ptr << endl;       // 30

    // Difference between pointers
    int* start = arr;
    int* end = &arr[4];
    cout << "Number of elements between: " << (end - start) << endl;  // 4

    // Compare pointers
    if (start < end) cout << "start is before end" << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int numbers[] = {5, 10, 15, 20};

    // Array name acts as pointer to first element
    int* ptr = numbers;  // same as &numbers[0]

    // Accessing via pointer arithmetic
    for (int i = 0; i < 4; i++) {
        cout << *(numbers + i) << " ";   // numbers[i]
    }
    cout << endl;

    // Using pointer to iterate
    for (int* p = numbers; p < numbers + 4; p++) {
        cout << *p << " ";
    }
    cout << endl;

    // sizeof difference: array vs pointer
    cout << "Size of array: " << sizeof(numbers) << " bytes" << endl;
    cout << "Size of pointer: " << sizeof(ptr) << " bytes" << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int value = 42;
    int* ptr = &value;      // pointer to int
    int** ptr2 = &ptr;      // pointer to pointer to int

    cout << "value = " << value << endl;
    cout << "*ptr = " << *ptr << endl;
    cout << "**ptr2 = " << **ptr2 << endl;

    // Changing value through double pointer
    **ptr2 = 99;
    cout << "After **ptr2 = 99, value = " << value << endl;

    // Repointing the original pointer via double pointer
    int another = 100;
    *ptr2 = &another;       // changes ptr to point to another
    cout << "Now *ptr = " << *ptr << endl;  // 100

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 20;

    // 1. Pointer to const: cannot change the value via pointer
    const int* p1 = &a;
    // *p1 = 30;  // ERROR: *p1 is const
    p1 = &b;      // OK: pointer itself can change

    // 2. Const pointer: cannot change where it points
    int* const p2 = &a;
    *p2 = 30;     // OK: can change value
    // p2 = &b;   // ERROR: p2 is const

    // 3. Const pointer to const: cannot change either
    const int* const p3 = &a;
    // *p3 = 30;  // ERROR
    // p3 = &b;   // ERROR

    // 4. Pointer to non-const (normal)
    int* p4 = &a;
    *p4 = 50;
    p4 = &b;

    cout << "a = " << a << ", b = " << b << endl;

    // Common use: function parameter to avoid copying but prevent modification
    // void print(const int* p) { ... }

    return 0;
}

